import React from 'react';

import jobs from '../data/jobs.json';
import courses from '../data/courses.json';
import studies from '../data/studies.json';
import pageCSS from './page.module.css';
import css from './about.module.css';

import Title from '../components/Title';
import TextBlock from '../components/TextBlock';
import Header from '../components/Header';

export default function About() {
	const pageName = 'About Me';

	return (
		<div className={pageCSS.pageContainer}>
			<Header pageName={pageName} />
			<div className={pageCSS.pageContent}>
				<Title title={pageName} />
				<div className={css.information}>
					Lorem ipsum dolor sit amet, consectetur adipiscing elit. Quisque eu ipsum ut urna condimentum accumsan a
					auctor nulla. Donec bibendum dolor dui, a mollis dui sodales in. Orci varius natoque penatibus et magnis dis
					parturient montes, nascetur ridiculus mus. Curabitur sodales viverra tempus. Vestibulum ornare auctor ligula,
					ac tincidunt arcu dapibus a. Nulla arcu sapien, fermentum iaculis posuere vitae, fermentum vitae urna. Duis ut
					rhoncus mi. Fusce ultrices nisi a ligula commodo, eu vulputate tellus commodo. Duis lacinia libero eget elit
					fringilla, quis auctor nulla dapibus. Fusce sagittis dui neque, quis consequat mi lobortis nec. Cras sit amet
					nibh non felis sodales commodo. Vivamus purus odio, tempus sit amet felis sed, efficitur venenatis orci.
					Nullam pellentesque vehicula consequat. Morbi bibendum lectus diam. Pellentesque accumsan tempor urna at
					placerat. Cras aliquam dui eget interdum elementum. Sed nec diam quis lorem tristique consequat eget eget
					metus. Nam nulla nisl, blandit sed lorem sit amet, dapibus gravida ante. Integer sollicitudin vulputate sapien
					et faucibus. In nec posuere massa.
				</div>

				<h2 className={css.subtitle}>So far what I have done?</h2>
				{jobs.map(({ id, enterprise, role, description, from, to }) => {
					return <TextBlock key={id} title={role} from={from} to={to} text={description} subtitle={enterprise} />;
				})}

				<h2 className={css.subtitle}>Academic Education</h2>
				{studies.map(({ id, institute, course, description, from, to }) => {
					return <TextBlock key={id} title={course} from={from} to={to} text={description} subtitle={institute} />;
				})}
			</div>
		</div>
	);
}
